    Int(i64),
    Float(f64),
}

fn str2num_stub(bytes: &[u8]) -> Option<NumResult> {
    let s = bytes.iter().position(|&b| b == 0)
        .map(|n| &bytes[..n])
        .unwrap_or(bytes);
    let mut value = lua_types::LuaValue::Nil;
    if lua_vm::object::str2num(s, &mut value) == 0 {
        return None;
    }
    match value {
        lua_types::LuaValue::Int(i) => Some(NumResult::Int(i)),
